const sender_id = String($('Set Buffered Conversation Context').first().json.sender_id || '').trim();

const isHttpUrl = (value) => /^https?:\/\//i.test(String(value || '').trim());
const products = Array.isArray($json.output?.product) ? $json.output.product : [];

const elements = products
  .map((item, index) => {
    const imageUrl = String(item.image || '').trim();
    if (!isHttpUrl(imageUrl)) return null;

    const websiteUrl = String(item.website_url || '').trim();
    const hasWebsiteUrl = isHttpUrl(websiteUrl);

    const title = String(item.title || `San pham ${index + 1}`)
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 80);

    const subtitle = [
      item.price ? `Giá bán: ${String(item.price).trim()}` : '',
      item.size ? `Size: ${String(item.size).trim()}` : '',
      item.variant ? String(item.variant).trim() : '',
    ].filter(Boolean).join(' | ').slice(0, 80);

    const element = {
      title,
      image_url: imageUrl,
      subtitle,
    };

    if (hasWebsiteUrl) {
      element.default_action = {
        type: 'web_url',
        url: websiteUrl,
        webview_height_ratio: 'full',
      };
      element.buttons = [
        {
          type: 'web_url',
          url: websiteUrl,
          title: 'Xem chi tiết',
          webview_height_ratio: 'full',
        },
      ];
    }

    return element;
  })
  .filter(Boolean)
  .slice(0, 5);

return [{ json: { sender_id, elements } }];

